<?php require_once __DIR__.'/../../middleware/bootstrap.php';require_once __DIR__.'/../../reloadly/client.php';$u=user();$d=input();$pdo=db();$st=$pdo->prepare('select * from gift_cards where id=? and enabled=1');$st->execute([$d['product_id']??0]);$p=$st->fetch();if(!$p)out(['error'=>'Product not found'],404);$w=$pdo->prepare('select * from wallets where user_id=? for update');$pdo->beginTransaction();$w->execute([$u['id']]);$wal=$w->fetch();if($wal['balance']<$p['price']){$pdo->rollBack();out(['error'=>'Insufficient wallet balance'],402);} $pdo->prepare('update wallets set balance=balance-? where user_id=?')->execute([$p['price'],$u['id']]);$pdo->prepare('insert into orders(user_id,total,currency,status,created_at)values(?,?,?,"paid",now())')->execute([$u['id'],$p['price'],$p['currency']]);$oid=$pdo->lastInsertId();$pdo->prepare('insert into order_items(order_id,gift_card_id,quantity,unit_price,total)values(?,?,?,?,?)')->execute([$oid,$p['id'],1,$p['price'],$p['price']]);$pdo->prepare('insert into transactions(user_id,type,amount,status,reference,created_at)values(?,"purchase",?,"completed",?,now())')->execute([$u['id'],-$p['price'],'order-'.$oid]);$pdo->commit();out(['ok'=>true,'order_id'=>$oid]);
